define i1 @sext_square_bit14(i8 noundef %x) {
  %sx = sext i8 %x to i32
  %mul = mul nsw i32 %sx, %sx
  %cmp = icmp samesign ugt i32 %mul, 16383
  ret i1 %cmp
}

```
